package com.google.gson.internal;
import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Method;
import java.util.List;
import com.google.gson.ReflectionAccessFilter;
import com.google.gson.ReflectionAccessFilter.FilterResult;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class ReflectionAccessFilterHelperTest {

  @Test
  void testIsAnyPlatformType_withAndroidType() throws Exception {
    // Android class name starts with "android."
    Class<?> androidClass = Class.forName("android.app.Activity");
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(androidClass);
    assertTrue(result);
  }

  @Test
  void testIsAnyPlatformType_withJavaType() throws Exception {
    // Java class name starts with "java."
    Class<?> javaClass = String.class;
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(javaClass);
    assertTrue(result);
  }

  @Test
  void testIsAnyPlatformType_withKotlinType() {
    Class<?> kotlinClass = DummyKotlin.class;
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(kotlinClass);
    assertTrue(result);
  }

  @Test
  void testIsAnyPlatformType_withKotlinxType() {
    Class<?> kotlinxClass = DummyKotlinx.class;
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(kotlinxClass);
    assertTrue(result);
  }

  @Test
  void testIsAnyPlatformType_withScalaType() {
    Class<?> scalaClass = DummyScala.class;
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(scalaClass);
    assertTrue(result);
  }

  @Test
  void testIsAnyPlatformType_withNonPlatformType() {
    Class<?> nonPlatformClass = DummyNonPlatform.class;
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(nonPlatformClass);
    assertFalse(result);
  }

  // Dummy classes for testing prefixes
  static class DummyKotlin {
    public String getName() {
      return "kotlin.DummyKotlin";
    }
  }

  static class DummyKotlinx {
    public String getName() {
      return "kotlinx.DummyKotlinx";
    }
  }

  static class DummyScala {
    public String getName() {
      return "scala.DummyScala";
    }
  }

  static class DummyNonPlatform {
    public String getName() {
      return "dummy.NonPlatform";
    }
  }
}
